package main

import (
	"fmt"
	"net/http"
	"io/ioutil"
)

func main() {
	// On crée une requête HTTP GET vers une URL donnée
	resp, err := http.Get("https://www.google.com")
	if err != nil {
		fmt.Println("Erreur lors de l'exécution de la requête:", err)
		return
	}
	defer resp.Body.Close()

	// On lit le corps de la réponse
	body, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		fmt.Println("Erreur lors de la lecture du corps de la réponse:", err)
		return
	}

	// On imprime le contenu de la réponse
	fmt.Println("Contenu de la réponse :")
	fmt.Println(string(body))
}
```

Ce petit programme utilise la bibliothèque `net/http` pour envoyer une requête GET et récupérer la réponse. Ensuite, il lit le corps de cette réponse et l'affiche à l'écran. N'oublie pas de gérer correctement les erreurs et de clore le corps de la réponse une fois que tu as fini de le lire!

