#include <iostream>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int fd[2];  // Nous créons un petit tube pour la communication
    pipe(fd);  // Créons un descripteur de tube

    pid_t pid = fork();  // Nous créons un nouveau processus
    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus" << std::endl;
        return 1;
    } else if (pid == 0) {  // Si nous sommes dans le processus fils
        close(fd[1]);  // Nous ne voulons pas écrire dans le tube
        dup2(fd[0], STDIN_FILENO);  // Nous connectons l'entrée du processus à notre tube
        close(fd[0]);  // Nous fermons le descripteur non nécessaire

        execlp("ls", "ls", "-l", (char *)0);  // Exécutons un programme (ici "ls -l")
        std::cerr << "Erreur lors de l'exécution de ls" << std::endl;
        _exit(1);  // Sortir proprement
    } else {  // Si nous sommes dans le processus père
        close(fd[0]);  // Nous ne voulons pas lire depuis le tube

        char buffer[100];
        std::cout << "Entrez ce que vous voulez envoyer au processus fils : ";
        std::cin.getline(buffer, 100);
        write(fd[1], buffer, strlen(buffer));  // Envoyons le message

        close(fd[1]);  // Fermez le descripteur de sortie

        wait(NULL);  // Attendons que le processus fils se termine
        std::cout << "Processus fils a terminé." << std::endl;
    }

    return 0;
}
